module top_module(
	input clk, adj_clk,
	input wire adjust,
	output clock
    );reg clock_reg;

always @* begin
	if (adjust == 0) 
		clock_reg = clk;
	else 
	    clock_reg = adj_clk;

end

assign clock = clock_reg;

  always @(*) begin
    if (1'b0) begin
      if (adjust == 1'b1) begin
        clock_reg <= adj_clk;
      end else begin
        clock_reg <= clk;
      end;
    end
  end

endmodule

